          </div>
        ) : (
          /* Upload Interface */
          <div className="w-full flex flex-col items-center animate-fade-in">
             {!isProcessing ? (
                <div 
                  className="w-full h-48 border-2 border-dashed border-indigo-200 rounded-3xl bg-indigo-50/50 flex flex-col items-center justify-center cursor-pointer hover:bg-indigo-50 transition-colors"
                  onClick={() => fileInputRef.current?.click()}
                >
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="audio/*" 
                    onChange={handleFileUpload}
                  />
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-sm mb-4">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                    </svg>
                  </div>
                  <p className="text-indigo-900 font-medium">Click to upload audio file</p>
                  <p className="text-indigo-400 text-sm mt-1">MP3, WAV, M4A (Max 10MB)</p>
                </div>
             ) : null}
          </div>
        )}

        {isProcessing && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 z-10 backdrop-blur-sm rounded-3xl">
            <div className="flex items-center justify-center space-x-3 text-indigo-600 py-4">
              <svg className="animate-spin h-8 w-8" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            </div>
            <span className="text-xl font-medium text-indigo-900">
              {isAnalyzing 
                ? 'Checking Audio Quality...' 
                : (mode === 'record' ? 'Transcribing Recording...' : 'Processing File...')
              }
            </span>
            <p className="text-slate-500 mt-2">
              {isAnalyzing 
                ? 'Analyzing volume and clarity.' 
                : 'Generating structured notes. This may take a moment.'
              }
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not set");
  }
  return new GoogleGenAI({ apiKey });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove the data URL prefix (e.g., "data:audio/webm;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const transcribeAudio = async (
  audioBlob: Blob, 
  language: string = 'Auto-detect', 
  template?: string,
  context?: string,
  isJsonMode: boolean = false
): Promise<{ text: string, json?: any }> => {
  try {
    // Safety check for size before attempting to read into memory
    if (audioBlob.size > 10 * 1024 * 1024) {
       throw new Error("Audio file too large. Please keep recordings under 10MB to avoid API limits.");
    }

    const ai = getGeminiClient();
    const base64Data = await blobToBase64(audioBlob);
    const mimeType = audioBlob.type || 'audio/webm';

    let systemInstruction = "You are an expert transcriber and meeting secretary. Your task is to analyze audio and produce clear, structured output.";

    // Inject Context/Vocabulary into the system instruction for better grounding
    if (context && context.trim().length > 0) {
      systemInstruction += `\n\nCONTEXT & VOCABULARY:\nUse the following context to correctly identify names, roles, acronyms, and specific facts mentioned in the audio:\n${context}`;
    }

    let prompt = "";

    if (isJsonMode) {
      prompt = `Analyze the speech in this audio file and extract information to fill out the requested fields.

      INSTRUCTIONS:
      ${template}

      IMPORTANT:
      - Return ONLY valid JSON.
      - Do not include markdown formatting like \`\`\`json.
      - Ensure all keys requested in the instructions are present in the JSON object.
      `;
    } else {
      prompt = "Analyze the speech in this audio file. Create a comprehensive set of structured neat notes that capture all key points, details, and arguments. Use clear headings, bullet points, and paragraphs. Output valid Markdown.";

      if (template && template.trim().length > 0) {
         prompt = `Analyze the speech in this audio file and extract information to fill out the following template.

         STRICTLY FOLLOW THIS STRUCTURE AND FORMAT:
         ${template}

         Instructions:
         1. Fill in the bracketed placeholders [ ] with information from the audio.
         2. Maintain the headings and structure exactly as provided in the template.
         3. Output valid Markdown.
         `;
      }
    }

    if (language && language !== 'Auto-detect') {
      prompt += `\n\nIMPORTANT: The language of the content must be ${language}.`;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Data } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: isJsonMode ? 'application/json' : 'text/plain'
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No transcription generated.");
    }

    if (isJsonMode) {
      try {
        const json = JSON.parse(text);
        return { text: JSON.stringify(json, null, 2), json };
      } catch (e) {
        console.error("Failed to parse JSON response:", e);
        // Fallback to text if JSON parsing fails, though responseMimeType should prevent this
        return { text };
      }
    }

    return { text };
  } catch (error: any) {
    console.error("Transcription error:", error);
    // Provide a more helpful error message for common issues
    if (error.message && error.message.includes('Rpc failed')) {
      throw new Error("Network error during transcription. The file may be too large or the connection was interrupted. Please try a shorter recording.");
    }
    throw new Error(error.message || "Failed to transcribe audio.");
  }
};

import React, { useRef, useState } from 'react';

export interface TemplateSelectorProps {
  template: string;
  onTemplateChange: (template: string) => void;
  context: string;
  onContextChange: (context: string) => void;
  mode: 'general' | 'meeting' | 'custom' | 'word_template';
  onModeChange: (mode: 'general' | 'meeting' | 'custom' | 'word_template') => void;
  wordTemplateName: string | null;
  onWordTemplateUpload: (file: File) => void;
}

export const MEETING_TEMPLATE = `# Meeting Minutes

**Title of Meeting:** [Extract Title]
**Date of Meeting:** [Extract Date]
**Members Present:** [List Members]

## Objective of Meeting
[Summarize the main objective]

## Points of Discussion
- [Point 1]
- [Point 2]
- [Point 3]

## Decisions Made
- [Decision 1]
- [Decision 2]

## Next Steps
- [Action Item 1] (Assignee: [Name])
- [Action Item 2] (Assignee: [Name])
`;

// Instructions for the JSON extraction when using a Word template
export const WORD_TEMPLATE_INSTRUCTIONS = `Extract the following information from the audio to fill a Word document template:

- title: The title of the meeting or note.
- date: The date of the recording.
- transcription: The full, verbatim text of the voice memo.
- summary: A concise summary of the content.
- key_points: A list of key points (as text with bullets).
- action_items: A list of action items or next steps.

Return the result as a valid JSON object with these exact keys.
`;

export const TemplateSelector: React.FC<TemplateSelectorProps> = ({
  template,
  onTemplateChange,
  context,
  onContextChange,
  mode,
  onModeChange,
  wordTemplateName,
  onWordTemplateUpload
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const wordInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleModeChange = (newMode: 'general' | 'meeting' | 'custom' | 'word_template') => {
    onModeChange(newMode);
    if (newMode === 'meeting') {
      onTemplateChange(MEETING_TEMPLATE);
    } else if (newMode === 'general') {
      onTemplateChange('');
    } else if (newMode === 'word_template') {
       // Set default instructions only if user hasn't set custom ones or it was the default
       if (!template || template === MEETING_TEMPLATE) {
         onTemplateChange(WORD_TEMPLATE_INSTRUCTIONS);
       }
    }

    if (newMode === 'custom' && mode === 'general') {
        onTemplateChange(MEETING_TEMPLATE); 
    }
  };

  const handleTextFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const text = event.target?.result as string;
        onTemplateChange(text);
        onModeChange('custom');
      };
      reader.readAsText(file);
    }
  };

  const handleWordFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      onWordTemplateUpload(file);
    }
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = () => {
    setIsDragging(false);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files[0];
    if (file && (file.name.endsWith('.docx') || file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document')) {
      onWordTemplateUpload(file);
    } else {
      alert("Please upload a valid .docx Word file.");
    }
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 mb-6 shadow-sm animate-fade-in divide-y divide-slate-100">

      {/* Output Format Selector */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 pb-4">
        <div>
           <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider">Output Format</h3>
           <p className="text-xs text-slate-500">Choose how to structure the notes</p>
        </div>

        <div className="flex flex-wrap gap-1 bg-slate-100 rounded-lg p-1">
          <button
            onClick={() => handleModeChange('general')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'general' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            General
          </button>
          <button
            onClick={() => handleModeChange('meeting')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'meeting' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Meeting Minutes
          </button>
          <button
            onClick={() => handleModeChange('custom')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'custom' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Custom Text
          </button>
          <button
            onClick={() => handleModeChange('word_template')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'word_template' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Word Template
          </button>
        </div>
      </div>

      {/* Main Template Editor */}
      <div className="py-4">
        {mode === 'word_template' && (
          <div className="space-y-4 animate-fade-in">
            <div 
              onDragOver={onDragOver}
              onDragLeave={onDragLeave}
              onDrop={onDrop}
              className={`relative group border-2 border-dashed rounded-2xl p-6 transition-all duration-200 text-center ${
                isDragging 
                  ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' 
                  : 'border-indigo-200 bg-indigo-50/50 hover:bg-indigo-50 hover:border-indigo-300'
              }`}
            >
              <div className="flex flex-col items-center">
                <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-3 transition-colors ${isDragging ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm'}`}>
                  {isDragging ? (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 animate-bounce" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                  ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                    </svg>
                  )}
                </div>

                <h4 className={`text-sm font-bold mb-1 ${isDragging ? 'text-indigo-700' : 'text-indigo-900'}`}>
                  {isDragging ? 'Drop Word File Now' : '1. Upload Word Document Design'}
