import { GoogleGenAI } from "@google/genai";

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not set");
  }
  return new GoogleGenAI({ apiKey });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove the data URL prefix (e.g., "data:audio/webm;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

const buildSystemInstruction = (context?: string) => {
  let instruction = "You are an expert transcriber and meeting secretary. Your task is to analyze content and produce clear, structured output.";
  if (context && context.trim().length > 0) {
    instruction += `\n\nCONTEXT & VOCABULARY:\nUse the following context to correctly identify names, roles, acronyms, and specific facts mentioned in the content:\n${context}`;
  }
  return instruction;
};

const buildPrompt = (template: string, isJsonMode: boolean, language: string) => {
  let prompt = "";
  if (isJsonMode) {
    prompt = `Analyze the provided content and extract information to fill out the requested fields.\n\nINSTRUCTIONS:\n${template}\n\nIMPORTANT:\n- Return ONLY valid JSON.\n- Do not include markdown formatting like \`\`\`json.\n- Ensure all keys requested in the instructions are present in the JSON object.`;
  } else {
    prompt = "Analyze the provided content. Create a comprehensive set of structured neat notes that capture all key points, details, and arguments. Use clear headings, bullet points, and paragraphs. Output valid Markdown.";
    if (template && template.trim().length > 0) {
      prompt = `Analyze the provided content and extract information to fill out the following template.\n\nSTRICTLY FOLLOW THIS STRUCTURE AND FORMAT:\n${template}\n\nInstructions:\n1. Fill in the bracketed placeholders [ ] with information from the content.\n2. Maintain the headings and structure exactly as provided in the template.\n3. Output valid Markdown.`;
    }
  }

  if (language && language !== 'Auto-detect') {
    prompt += `\n\nIMPORTANT: The language of the content must be ${language}.`;
  }
  return prompt;
};

export const processText = async (
  inputText: string,
  language: string = 'Auto-detect',
  template?: string,
  context?: string,
  isJsonMode: boolean = false
): Promise<{ text: string, json?: any }> => {
  try {
    const ai = getGeminiClient();
    const systemInstruction = buildSystemInstruction(context);
    const prompt = buildPrompt(template || "", isJsonMode, language);

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Content to process:\n${inputText}\n\nInstruction:\n${prompt}`,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: isJsonMode ? 'application/json' : 'text/plain'
      }
    });

    const text = response.text;
    if (!text) throw new Error("No output generated.");

    if (isJsonMode) {
      try {
        const json = JSON.parse(text);
        return { text: JSON.stringify(json, null, 2), json };
      } catch (e) {
        return { text };
      }
    }
    return { text };
  } catch (error: any) {
    throw new Error(error.message || "Failed to process text.");
  }
};

export const transcribeAudio = async (
  audioBlob: Blob, 
  language: string = 'Auto-detect', 
  template?: string,
  context?: string,
  isJsonMode: boolean = false
): Promise<{ text: string, json?: any }> => {
  try {
    if (audioBlob.size > 10 * 1024 * 1024) {
       throw new Error("Audio file too large. Please keep recordings under 10MB to avoid API limits.");
    }

    const ai = getGeminiClient();
    const base64Data = await blobToBase64(audioBlob);
    const mimeType = audioBlob.type || 'audio/webm';
    const systemInstruction = buildSystemInstruction(context);
    const prompt = buildPrompt(template || "", isJsonMode, language);

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Data } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: isJsonMode ? 'application/json' : 'text/plain'
      }
    });

    const text = response.text;
    if (!text) throw new Error("No transcription generated.");

    if (isJsonMode) {
      try {
        const json = JSON.parse(text);
        return { text: JSON.stringify(json, null, 2), json };
      } catch (e) {
        return { text };
      }
    }
    return { text };
  } catch (error: any) {
    if (error.message && error.message.includes('Rpc failed')) {
      throw new Error("Network error. The file may be too large or the connection was interrupted.");
    }
    throw new Error(error.message || "Failed to transcribe audio.");
  }
};

