const analyzeAudioQuality = async (blob: Blob): Promise<string | null> => {
  if (blob.size === 0) return "Audio file is empty.";
  if (blob.size > 10 * 1024 * 1024) return null;

  try {
    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    const arrayBuffer = await blob.arrayBuffer();
    const audioBuffer = await audioContext.decodeAudioData(arrayBuffer);

    if (audioBuffer.duration < 0.5) {
      audioContext.close();
      return "Recording is too short.";
    }

    const rawData = audioBuffer.getChannelData(0);
    let sum = 0;
    const sampleStep = Math.floor(rawData.length / 5000) || 1; 
    let samplesChecked = 0;

    for (let i = 0; i < rawData.length; i += sampleStep) {
      const sample = rawData[i];
      sum += sample * sample;
      samplesChecked++;
    }

    const rms = Math.sqrt(sum / samplesChecked);
    audioContext.close();

    if (rms < 0.005) return "Audio volume is extremely low.";
    return null;
  } catch (e) {
    return null; 
  }
};

export const AudioRecorder: React.FC<MediaInputProps> = ({
  onTranscriptionStart,
  onTranscriptionComplete,
  onTranscriptionError,
  currentState,
  template,
  context,
  isJsonMode
}) => {
  const [mode, setMode] = useState<'record' | 'upload' | 'text'>('record');
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [selectedLanguage, setSelectedLanguage] = useState('Auto-detect');
  const [manualText, setManualText] = useState('');

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [qualityWarning, setQualityWarning] = useState<string | null>(null);
  const [pendingBlob, setPendingBlob] = useState<Blob | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const timerRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
      }
    };
  }, []);

  const startRecording = async () => {
    setQualityWarning(null);
    setPendingBlob(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        stream.getTracks().forEach(track => track.stop());
        processAudio(blob);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setDuration(0);
      timerRef.current = window.setInterval(() => setDuration(prev => prev + 1), 1000);
    } catch (err) {
      onTranscriptionError("Could not access microphone.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQualityWarning(null);
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { 
        onTranscriptionError("File too large (Max 10MB).");
        return;
      }
      processAudio(file);
    }
  };

  const processAudio = async (blob: Blob) => {
    setIsAnalyzing(true);
    const warning = await analyzeAudioQuality(blob);
    setIsAnalyzing(false);

    if (warning) {
      setQualityWarning(warning);
      setPendingBlob(blob);
    } else {
      executeTranscription(blob);
    }
  };

  const executeTranscription = async (blob: Blob) => {
    onTranscriptionStart();
    try {
      const { transcribeAudio } = await import('../services/geminiService');
      const result = await transcribeAudio(blob, selectedLanguage, template, context, isJsonMode);
      onTranscriptionComplete(result.text, result.json);
    } catch (error: any) {
      onTranscriptionError(error.message);
    }
  };

  const handleProcessManualText = async () => {
    if (!manualText.trim()) return;
    onTranscriptionStart();
    try {
      const { processText } = await import('../services/geminiService');
      const result = await processText(manualText, selectedLanguage, template, context, isJsonMode);
      onTranscriptionComplete(result.text, result.json);
    } catch (error: any) {
      onTranscriptionError(error.message);
    }
  };

  const handleProceedAnyway = () => {
    if (pendingBlob) {
      setQualityWarning(null);
      executeTranscription(pendingBlob);
      setPendingBlob(null);
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isProcessing = currentState === 'processing' || isAnalyzing;

  return (
    <div className="flex flex-col items-center justify-center space-y-6 w-full max-w-xl mx-auto p-4 sm:p-6 relative">

      {qualityWarning && (
        <div className="absolute inset-0 bg-white/95 z-20 flex flex-col items-center justify-center p-6 text-center rounded-3xl animate-fade-in border-2 border-amber-100 shadow-xl">
          <div className="w-12 h-12 bg-amber-100 text-amber-500 rounded-full flex items-center justify-center mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h3 className="text-lg font-bold text-slate-800 mb-2">Audio Quality Warning</h3>
          <p className="text-slate-600 mb-6 text-sm">{qualityWarning}</p>
          <div className="flex w-full gap-3">
            <button onClick={() => setQualityWarning(null)} className="flex-1 px-4 py-2 border border-slate-200 text-slate-700 font-medium rounded-xl hover:bg-slate-50">Back</button>
            <button onClick={handleProceedAnyway} className="flex-1 px-4 py-2 bg-amber-500 text-white font-medium rounded-xl shadow-sm">Process Anyway</button>
          </div>
        </div>
      )}

      {!isRecording && !isProcessing && (
        <div className="w-full space-y-4 animate-fade-in">
          <div className="flex p-1.5 bg-slate-100 rounded-2xl">
            <button onClick={() => setMode('record')} className={`flex-1 py-2.5 text-sm font-semibold rounded-xl transition-all ${mode === 'record' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>Record</button>
            <button onClick={() => setMode('upload')} className={`flex-1 py-2.5 text-sm font-semibold rounded-xl transition-all ${mode === 'upload' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>Upload</button>
            <button onClick={() => setMode('text')} className={`flex-1 py-2.5 text-sm font-semibold rounded-xl transition-all ${mode === 'text' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>Paste Text</button>
          </div>

          <div className="flex items-center justify-center">
            <select
              value={selectedLanguage}
              onChange={(e) => setSelectedLanguage(e.target.value)}
              className="px-4 py-2 text-sm border-slate-200 focus:ring-2 focus:ring-indigo-500 rounded-xl bg-slate-50 text-slate-700 cursor-pointer outline-none transition-all hover:bg-white"
            >
              {LANGUAGES.map((lang) => <option key={lang} value={lang}>{lang}</option>)}
            </select>
          </div>
        </div>
      )}

      <div className="w-full min-h-[220px] flex items-center justify-center">
        {mode === 'record' && (
          <div className="flex flex-col items-center space-y-6 w-full">
            <div className={`relative flex items-center justify-center w-40 h-40 rounded-full border-4 transition-all duration-300 ${isRecording ? 'border-red-500 bg-red-50' : 'border-slate-100 bg-white'}`}>
              {isRecording ? (
                <div className="flex items-center space-x-1.5 h-16">
                  {[0, 100, 200, 300, 400].map(delay => (
                    <div key={delay} className="w-2 bg-red-500 h-8 rounded-full animate-wave" style={{ animationDelay: `${delay}ms` }}></div>
                  ))}
                </div>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                </svg>
              )}
              {isRecording && <div className="absolute -bottom-10 text-red-600 font-mono font-bold text-xl">{formatDuration(duration)}</div>}
            </div>
            {!isRecording && !isProcessing && (
              <button onClick={startRecording} className="w-full sm:w-64 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl shadow-lg font-bold text-lg flex items-center justify-center gap-3 transition-transform active:scale-95">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 18.5a6.5 6.5 0 100-13 6.5 6.5 0 000 13z" /></svg>
                Start Recording
              </button>
            )}
            {isRecording && (
              <button onClick={stopRecording} className="w-full sm:w-64 py-4 bg-white border-2 border-red-500 text-red-600 hover:bg-red-50 rounded-2xl shadow-md font-bold text-lg flex items-center justify-center gap-3 active:scale-95">
                <div className="w-4 h-4 bg-red-600 rounded-sm"></div>
                Stop Recording
              </button>
            )}
          </div>
        )}

        {mode === 'upload' && !isProcessing && (
          <div className="w-full animate-fade-in">
            <div onClick={() => fileInputRef.current?.click()} className="w-full h-48 border-2 border-dashed border-slate-200 rounded-3xl bg-slate-50/50 flex flex-col items-center justify-center cursor-pointer hover:bg-indigo-50 hover:border-indigo-200 transition-all group">
              <input type="file" ref={fileInputRef} className="hidden" accept="audio/*" onChange={handleFileUpload} />
              <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center shadow-sm mb-4 group-hover:scale-110 transition-transform">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
              </div>
              <p className="text-slate-800 font-bold text-lg">Upload Audio File</p>
              <p className="text-slate-500 text-sm mt-1">MP3, WAV, M4A (Max 10MB)</p>
            </div>
          </div>
        )}

        {mode === 'text' && !isProcessing && (
          <div className="w-full space-y-4 animate-fade-in">
            <textarea
              value={manualText}
              onChange={(e) => setManualText(e.target.value)}
              placeholder="Paste your raw notes or transcript here..."
              className="w-full h-48 p-4 text-sm font-sans text-slate-700 bg-white border border-slate-200 rounded-3xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none shadow-inner"
            />
            <button 
              onClick={handleProcessManualText}
              disabled={!manualText.trim()}
              className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white rounded-2xl shadow-lg font-bold text-lg transition-transform active:scale-95"
            >
              Process Text
            </button>
          </div>
        )}

        {isProcessing && (
          <div className="flex flex-col items-center justify-center animate-fade-in">
            <div className="relative">
              <svg className="animate-spin h-16 w-16 text-indigo-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            </div>
            <p className="mt-6 text-xl font-bold text-indigo-900">{isAnalyzing ? 'Analyzing Audio...' : 'AI is Thinking...'}</p>
            <p className="text-slate-500 mt-2 text-sm">Structuring your notes based on your template.</p>
          </div>
        )}
      </div>
    </div>
  );
};

