  });
  const [template, setTemplate] = useState<string>('');
  const [context, setContext] = useState<string>("Sara is in the BD (Business Development) department.\nTarek is the PDG (CEO).\nActivity: We presented 4 automations and 9 web applications.");
  const [templateMode, setTemplateMode] = useState<'general' | 'word_template'>('general');
  const [wordTemplateFile, setWordTemplateFile] = useState<ArrayBuffer | null>(null);
  const [wordTemplateName, setWordTemplateName] = useState<string | null>(null);

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string, json?: any) => {
    setState({ status: 'success', text, jsonResult: json, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error, jsonResult: null });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null, jsonResult: null });
  };

  const handleWordTemplateUpload = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        const arrayBuffer = e.target.result as ArrayBuffer;
        setWordTemplateFile(arrayBuffer);
        setWordTemplateName(file.name);

        // Auto-detect placeholders
        try {
          const zip = new PizZip(arrayBuffer);
          let detectedPlaceholders: string[] = [];

          // Microsoft Word XML parsing to find placeholders
          if (zip.files['word/document.xml']) {
             const docXml = zip.files['word/document.xml'].asText();

             // 1. Try standard regex on the raw XML (works for simple docs)
             const rawMatches = docXml.match(/\{[a-zA-Z0-9_]+\}/g);
             if (rawMatches) detectedPlaceholders.push(...rawMatches);

             // 2. Advanced: Concatenate all text nodes to handle split placeholders 
             // (e.g. <w:t>{</w:t><w:t>name</w:t><w:t>}</w:t>)
             const textNodeMatches = docXml.match(/<w:t[\s\S]*?>([\s\S]*?)<\/w:t>/g);
             if (textNodeMatches) {
                const fullText = textNodeMatches.map((t: string) => t.replace(/<[^>]+>/g, '')).join('');
                const joinedMatches = fullText.match(/\{[a-zA-Z0-9_]+\}/g);
                if (joinedMatches) detectedPlaceholders.push(...joinedMatches);
             }
          }

          if (detectedPlaceholders.length > 0) {
            // Clean up duplicates and braces
            const vars = detectedPlaceholders.map((m: string) => m.replace(/[\{\}]/g, ''));
            const uniqueVars = [...new Set(vars)];

            const newInstruction = `The uploaded Word template contains the following placeholders:
${uniqueVars.map(v => `- ${v}`).join('\n')}

Instructions:
1. Analyze the content and extract data for the keys above.
2. Return a valid JSON object matching these keys exactly.
3. If a key seems to request the full text (e.g. 'transcript', 'transcription', 'full_text', 'notes', 'memo'), provide the complete text.
4. For other keys, extract the specific details requested.
5. If information is missing, use " ".`;

            setTemplate(newInstruction);
          } else {
             // Fallback if we couldn't detect simple placeholders
             setTemplate(WORD_TEMPLATE_INSTRUCTIONS + "\n\n(No specific placeholders were detected in the uploaded file. Please ensure your Word document uses {brackets} for fields.)");
          }
        } catch (err) {
           console.warn("Failed to analyze template placeholders", err);
           setTemplate(WORD_TEMPLATE_INSTRUCTIONS);
        }
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const handleExportWord = () => {
    // If we have a JSON result and a Word template, use docxtemplater
    if (state.jsonResult && wordTemplateFile && templateMode === 'word_template') {
       try {
         const zip = new PizZip(wordTemplateFile);
         const doc = new docxtemplater(zip, {
            paragraphLoop: true,
            linebreaks: true,
            // Robustly handle missing keys by returning an empty string instead of throwing error
            nullGetter: (part: any) => {
                if (!part.module) return "";
                if (part.module === "rawxml") return "";
                return "";
            }
         });

         // Render the document with the JSON data from Gemini
         doc.render(state.jsonResult);

         const out = doc.getZip().generate({
            type: "blob",
            mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
         });

         saveAs(out, `filled_${wordTemplateName || 'document.docx'}`);
       } catch (error: any) {
          console.error("Docxtemplater error:", error);

          let msg = "Error generating Word document.";
          if (error.properties && error.properties.errors) {
              const errs = error.properties.errors.map((e: any) => e.message).join(', ');
              msg += ` Details: ${errs}`;
          }
          alert(msg);
       }
       return;
    }

    // Fallback: Export standard Markdown/HTML to Word
    if (!state.text) return;

    let htmlContent = '';
    if (typeof marked !== 'undefined') {
       htmlContent = marked.parse(state.text);
    } else {
       htmlContent = `<pre>${state.text}</pre>`;
    }

    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' " +
         "xmlns:w='urn:schemas-microsoft-com:office:word' " +
         "xmlns='http://www.w3.org/TR/REC-html40'>" +
         "<head><meta charset='utf-8'><title>Export HTML to Word Document with JavaScript</title>" +
         "<style>body { font-family: 'Calibri', sans-serif; font-size: 11pt; }</style>" +
         "</head><body>";
    const footer = "</body></html>";
    const sourceHTML = header + htmlContent + footer;

    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = 'meeting_notes.doc';
    fileDownload.click();
    document.body.removeChild(fileDownload);
  };

  const getMarkdownHtml = (text: string | null) => {
    if (!text) return { __html: '' };
    if (typeof marked !== 'undefined') {
      return { __html: marked.parse(text) };
    }
    return { __html: text };
  };

  const isWordTemplateMode = templateMode === 'word_template';

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-indigo-100 selection:text-indigo-800">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 no-print">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
              Gemini Transcribe
            </h1>
          </div>
          <div className="text-xs font-medium px-2.5 py-1 bg-indigo-50 text-indigo-700 rounded-full border border-indigo-100">
            Powered by Gemini 2.5 Flash
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-12 sm:px-6 lg:px-8">
        <div className="space-y-12">

          {/* Settings Section */}
          <section className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden no-print">
             <div className="p-6 pb-0">
               <TemplateSelector 
                  template={template} 
                  onTemplateChange={setTemplate}
                  context={context}
                  onContextChange={setContext}
                  mode={templateMode}
                  onModeChange={setTemplateMode}
                  wordTemplateName={wordTemplateName}
                  onWordTemplateUpload={handleWordTemplateUpload}
               />
             </div>
             <div className="p-1 border-t border-slate-100">
               <AudioRecorder
                currentState={state.status}
                onTranscriptionStart={handleStart}
                onTranscriptionComplete={handleComplete}
                onTranscriptionError={handleError}
                template={template}
                context={context}
                isJsonMode={isWordTemplateMode}
              />
             </div>
          </section>

          {/* Error Message */}
          {state.status === 'error' && (
            <div className="bg-red-50 border border-red-200 rounded-2xl p-6 flex items-start space-x-4 animate-fade-in no-print">
              <div className="flex-shrink-0">
                <svg className="h-6 w-6 text-red-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div className="flex-1">
                <h3 className="text-sm font-medium text-red-800">Transcription Failed</h3>
                <p className="mt-1 text-sm text-red-700">{state.error}</p>
                <button 
                  onClick={reset}
                  className="mt-3 text-sm font-medium text-red-600 hover:text-red-500"
                >
                  Try Again &rarr;
                </button>
              </div>
            </div>
          )}

          {/* Results Section */}
          {state.status === 'success' && (
            <section className="space-y-4 animate-fade-in-up">
              <div className="flex items-center justify-between no-print flex-wrap gap-2">
                <h2 className="text-lg font-semibold text-slate-800">
                  {state.jsonResult ? 'Extracted Data' : 'Transcribed Notes'}
                </h2>
                <div className="flex space-x-2">
                   <button 
                    onClick={handleExportWord}
                    className="flex items-center space-x-2 px-3 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors shadow-sm text-sm font-medium"
                    title={isWordTemplateMode ? "Fill Word Template" : "Export as Word Doc"}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                       <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                    </svg>
                    <span>{isWordTemplateMode ? 'Download Filled Word Doc' : 'Export Word'}</span>
                  </button>

                  {!isWordTemplateMode && (
                    <button 
                      onClick={handlePrintPDF}
                      className="flex items-center space-x-2 px-3 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg transition-colors shadow-sm text-sm font-medium"
                      title="Export as PDF"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                      </svg>
                      <span>Export PDF</span>
                    </button>
                  )}

                  <button 
                    onClick={() => navigator.clipboard.writeText(state.text || "")}
                    className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                    title="Copy to clipboard"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                    </svg>
                  </button>
                  <button 
                    onClick={reset}
                    className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                    title="New recording"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                  </button>
                </div>
              </div>

              <div id="results-container" className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 md:p-10">
                <h1 className="text-3xl font-bold mb-6 hidden print-only">Transcribed Notes</h1>

                {/* Render JSON as text if in JSON mode, otherwise Render Markdown */}
                {state.jsonResult ? (
                  <div className="space-y-4">
                    <div className="bg-green-50 border border-green-200 rounded-lg p-4 flex items-start gap-3">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-green-600 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                         <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                       </svg>
                       <div>
                         <h3 className="text-green-800 font-semibold text-sm">Data Ready for Insertion</h3>
                         <p className="text-green-700 text-sm mt-1">
                           Gemini has successfully extracted the data below. Click the <strong>Download Filled Word Doc</strong> button to generate your final document.
                         </p>
                       </div>
                    </div>

                    <div className="bg-slate-50 p-4 rounded-lg font-mono text-sm overflow-x-auto border border-slate-200">
                      <pre className="text-indigo-700">{JSON.stringify(state.jsonResult, null, 2)}</pre>
                    </div>
                  </div>
                ) : (
                  <div 
                    className="prose prose-slate max-w-none prose-headings:font-semibold prose-a:text-indigo-600"
                    dangerouslySetInnerHTML={getMarkdownHtml(state.text)}
                  />
                )}
              </div>
            </section>
          )}
        </div>
      </main>

      {/* Simple Footer */}
      <footer className="py-8 text-center text-slate-400 text-sm no-print">
        <p>&copy; {new Date().getFullYear()} Gemini Audio Transcriber</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';

export interface TemplateSelectorProps {
  template: string;
  onTemplateChange: (template: string) => void;
  context: string;
  onContextChange: (context: string) => void;
  mode: 'general' | 'word_template';
  onModeChange: (mode: 'general' | 'word_template') => void;
  wordTemplateName: string | null;
  onWordTemplateUpload: (file: File) => void;
}

// Instructions for the JSON extraction when using a Word template
export const WORD_TEMPLATE_INSTRUCTIONS = `Extract the following information from the audio to fill a Word document template:

- title: The title of the content.
- date: The date.
- transcription: The full, verbatim text.
- summary: A concise summary of the content.
- key_points: A list of key points (as text with bullets).
- action_items: A list of action items or next steps.

Return the result as a valid JSON object with these exact keys.
`;

export const TemplateSelector: React.FC<TemplateSelectorProps> = ({
  template,
  onTemplateChange,
  context,
  onContextChange,
  mode,
  onModeChange,
  wordTemplateName,
  onWordTemplateUpload
}) => {
  const wordInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleModeChange = (newMode: 'general' | 'word_template') => {
    onModeChange(newMode);
    if (newMode === 'general') {
      onTemplateChange('');
    } else if (newMode === 'word_template') {
       if (!template) {
         onTemplateChange(WORD_TEMPLATE_INSTRUCTIONS);
       }
    }
  };

  const handleWordFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      onWordTemplateUpload(file);
    }
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = () => {
    setIsDragging(false);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files[0];
    if (file && (file.name.endsWith('.docx') || file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document')) {
      onWordTemplateUpload(file);
    } else {
      alert("Please upload a valid .docx Word file.");
    }
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 mb-6 shadow-sm animate-fade-in divide-y divide-slate-100">

      {/* Output Format Selector */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 pb-4">
        <div>
           <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider">Output Mode</h3>
           <p className="text-xs text-slate-500">Choose your analysis target</p>
        </div>

        <div className="flex flex-wrap gap-1 bg-slate-100 rounded-lg p-1">
          <button
            onClick={() => handleModeChange('general')}
            className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'general' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            General Analysis
          </button>
          <button
            onClick={() => handleModeChange('word_template')}
            className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'word_template' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Word Template
          </button>
        </div>
      </div>

      {/* Main Template Editor */}
      <div className="py-4">
        {mode === 'word_template' ? (
          <div className="space-y-4 animate-fade-in">
            <div 
              onDragOver={onDragOver}
              onDragLeave={onDragLeave}
              onDrop={onDrop}
              className={`relative group border-2 border-dashed rounded-2xl p-6 transition-all duration-200 text-center ${
                isDragging 
                  ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' 
                  : 'border-indigo-200 bg-indigo-50/50 hover:bg-indigo-50 hover:border-indigo-300'
              }`}
            >
              <div className="flex flex-col items-center">
                <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-3 transition-colors ${isDragging ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm'}`}>
                  {isDragging ? (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 animate-bounce" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                  ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                    </svg>
                  )}
                </div>

                <h4 className={`text-sm font-bold mb-1 ${isDragging ? 'text-indigo-700' : 'text-indigo-900'}`}>
                  {isDragging ? 'Drop Word File Now' : '1. Upload Word Document Design'}
                </h4>
                <p className="text-xs text-indigo-600/80 mb-4 px-4 max-w-xs mx-auto">
                  Drag and drop your .docx file here. Placeholders like <code>{`{client_name}`}</code> will be automatically detected.
                </p>

                <button 
                    onClick={() => wordInputRef.current?.click()}
                    className={`px-5 py-2 rounded-xl text-sm font-semibold transition-all shadow-sm flex items-center gap-2 ${
                      isDragging 
                        ? 'bg-indigo-600 text-white' 
                        : 'bg-white border border-indigo-200 text-indigo-700 hover:bg-indigo-100 hover:border-indigo-300'
                    }`}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                    </svg>
                    {wordTemplateName ? 'Change Template' : 'Select .docx File'}
                </button>
                <input 
                    type="file" 
                    ref={wordInputRef} 
                    className="hidden" 
                    accept=".docx,application/vnd.openxmlformats-officedocument.wordprocessingml.document" 
                    onChange={handleWordFileUpload}
                />
              </div>

              {wordTemplateName && (
                <div className="mt-4 flex items-center justify-center gap-2 text-sm text-green-700 font-medium">
                    <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                    Active: {wordTemplateName}
                </div>
              )}
            </div>

            <div className="pt-2">
                <h4 className="text-sm font-semibold text-slate-700 mb-2 flex items-center gap-2">
                  <span className="flex items-center justify-center w-5 h-5 rounded-full bg-slate-200 text-slate-600 text-[10px] font-bold">2</span>
                  Extraction Instructions
                </h4>
                <textarea
                  value={template}
                  onChange={(e) => onTemplateChange(e.target.value)}
                  placeholder="Extract the following keys: {title}, {date}..."
                  className="w-full h-32 p-3 text-sm font-mono text-slate-700 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-y shadow-inner"
                />
            </div>
          </div>
        ) : (
          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 flex flex-col items-center text-center">
            <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm mb-3">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            <h4 className="text-sm font-bold text-slate-800">General Analysis Mode</h4>
            <p className="text-xs text-slate-500 max-w-sm mt-1">
              AI will automatically structure your content into clear notes with headings and bullet points. Perfect for quick summaries.
            </p>
          </div>
        )}
      </div>

      {/* Context / Vocabulary Section */}
      <div className="pt-4">
        <div className="flex items-center gap-2 mb-2">
           <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider">Context & Vocabulary</h3>
           <span className="text-xs text-slate-400 font-normal px-2 py-0.5 bg-slate-100 rounded-full">Optional</span>
        </div>
        <p className="text-xs text-slate-500 mb-2">Provide names, acronyms, or specific facts the AI should know (e.g., "Tarek is PDG").</p>
        <textarea
          value={context}
          onChange={(e) => onContextChange(e.target.value)}
          placeholder="E.g. Sara is BD. Tarek is PDG..."
          className="w-full h-24 p-3 text-sm font-sans text-slate-700 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-y shadow-inner"
        />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AudioRecorder } from './components/AudioRecorder';
import { TemplateSelector, WORD_TEMPLATE_INSTRUCTIONS, PV_TEMPLATE_INSTRUCTIONS } from './components/TemplateSelector';
import { TranscriptionState } from './types';

// Declare globals for libraries loaded via script tags
declare const marked: any;
declare const PizZip: any;
declare const docxtemplater: any;
declare const saveAs: any;

const App: React.FC = () => {
  const [state, setState] = useState<TranscriptionState>({
    status: 'idle',
    text: null,
    error: null,
    jsonResult: null
  });
  const [template, setTemplate] = useState<string>('');
  const [context, setContext] = useState<string>("Sara is in the BD (Business Development) department.\nTarek is the PDG (CEO).\nActivity: We presented 4 automations and 9 web applications.");
  const [templateMode, setTemplateMode] = useState<'general' | 'word_template' | 'pv_meeting'>('pv_meeting');
  const [wordTemplateFile, setWordTemplateFile] = useState<ArrayBuffer | null>(null);
  const [wordTemplateName, setWordTemplateName] = useState<string | null>(null);

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string, json?: any) => {
    setState({ status: 'success', text, jsonResult: json, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error, jsonResult: null });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null, jsonResult: null });
  };

  const handleWordTemplateUpload = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        const arrayBuffer = e.target.result as ArrayBuffer;
        setWordTemplateFile(arrayBuffer);
        setWordTemplateName(file.name);

        try {
          const zip = new PizZip(arrayBuffer);
          let detectedPlaceholders: string[] = [];
          if (zip.files['word/document.xml']) {
             const docXml = zip.files['word/document.xml'].asText();
             const rawMatches = docXml.match(/\{[a-zA-Z0-9_]+\}/g);
             if (rawMatches) detectedPlaceholders.push(...rawMatches);
          }

          if (detectedPlaceholders.length > 0) {
            const vars = detectedPlaceholders.map((m: string) => m.replace(/[\{\}]/g, ''));
            const uniqueVars = [...new Set(vars)];
            const newInstruction = `The uploaded Word template contains placeholders. Extract:\n${uniqueVars.map(v => `- ${v}`).join('\n')}\nReturn valid JSON.`;
            setTemplate(newInstruction);
          } else {
             setTemplate(WORD_TEMPLATE_INSTRUCTIONS);
          }
        } catch (err) {
           setTemplate(WORD_TEMPLATE_INSTRUCTIONS);
        }
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const handleExportWord = () => {
    if (state.jsonResult && wordTemplateFile && templateMode === 'word_template') {
       try {
         const zip = new PizZip(wordTemplateFile);
         const doc = new docxtemplater(zip, {
            paragraphLoop: true,
            linebreaks: true,
            nullGetter: () => ""
         });
         doc.render(state.jsonResult);
         const out = doc.getZip().generate({
            type: "blob",
            mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
         });
         saveAs(out, `filled_${wordTemplateName || 'document.docx'}`);
       } catch (error: any) {
          alert("Error generating Word document.");
       }
       return;
    }

    if (!state.text) return;
    let htmlContent = typeof marked !== 'undefined' ? marked.parse(state.text) : `<pre>${state.text}</pre>`;
    const header = "<html><head><meta charset='utf-8'></head><body>";
    const sourceHTML = header + htmlContent + "</body></html>";
    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    fileDownload.href = source;
    fileDownload.download = 'meeting_notes.doc';
    fileDownload.click();
  };

  const getMarkdownHtml = (text: string | null) => {
    if (!text) return { __html: '' };
    return { __html: typeof marked !== 'undefined' ? marked.parse(text) : text };
  };

  const renderPVMeeting = (data: any) => {
    return (
      <div className="bg-white p-4 sm:p-8 text-slate-800 text-[11pt] leading-relaxed max-w-full overflow-hidden">
        {/* Header Table */}
        <div className="grid grid-cols-12 border border-slate-400 mb-6">
          <div className="col-span-4 border-r border-slate-400 p-4 flex flex-col items-center justify-center">
            <div className="font-bold text-center tracking-tighter leading-none mb-1">GOLDEN CARTHAGE</div>
            <div className="text-[8px] text-center opacity-70">TUNIS</div>
          </div>
          <div className="col-span-4 border-r border-slate-400 p-4 flex items-center justify-center text-center font-bold text-lg italic">
            PV de réunion
          </div>
          <div className="col-span-4 text-[9px] uppercase">
            <div className="border-b border-slate-400 p-1 flex justify-between"><span>Réf:</span> <span className="font-mono">{data.ref || 'QUA-ENR-03'}</span></div>
            <div className="border-b border-slate-400 p-1 flex justify-between"><span>Version:</span> <span className="font-mono">{data.version || '00'}</span></div>
            <div className="border-b border-slate-400 p-1 flex justify-between"><span>Date:</span> <span className="font-mono">{data.date || new Date().toLocaleDateString('fr-FR')}</span></div>
            <div className="p-1 flex justify-between"><span>Page:</span> <span className="font-mono">1 sur 1</span></div>
          </div>
        </div>

        {/* PV Num Bar */}
        <div className="bg-[#7fb442] text-white font-bold p-1 px-3 mb-1 border border-slate-400">
          N° de PV : <span className="font-normal">{data.pv_num || '________________'}</span>
        </div>

        {/* Info Box */}
        <div className="border border-slate-400 mb-6 overflow-hidden">
          <div className="flex border-b border-slate-400">
            <div className="bg-[#7fb442] text-white p-2 font-bold w-40 flex-shrink-0">Date:</div>
            <div className="p-2 flex-grow">{data.date || '________________'}</div>
          </div>
          <div className="flex border-b border-slate-400">
            <div className="bg-[#7fb442] text-white p-2 font-bold w-40 flex-shrink-0">EQUIPE concernée :</div>
            <div className="p-2 flex-grow">{data.team || '________________'}</div>
          </div>
          <div className="flex">
            <div className="bg-[#7fb442] text-white p-2 font-bold w-40 flex-shrink-0">Ordre du jour :</div>
            <div className="p-2 flex-grow">{data.agenda || '________________'}</div>
          </div>
        </div>

        {/* Attendees Table */}
        <div className="mb-6">
          <div className="bg-[#7fb442] text-white font-bold text-center p-1 border-x border-t border-slate-400">Présents</div>
          <table className="w-full border-collapse border border-slate-400">
            <thead>
              <tr className="bg-slate-50 text-[10pt]">
                <th className="border border-slate-400 p-2 text-left w-1/3">Nom et prénom</th>
                <th className="border border-slate-400 p-2 text-left w-1/3">Visa</th>
                <th className="border border-slate-400 p-2 text-left w-1/3">Fonction</th>
              </tr>
            </thead>
            <tbody>
              {(data.attendees || [{}, {}, {}]).map((att: any, idx: number) => (
                <tr key={idx} className="h-8">
                  <td className="border border-slate-400 p-2">{att.name || ''}</td>
                  <td className="border border-slate-400 p-2 text-center opacity-30 text-xs italic">Electronique</td>
                  <td className="border border-slate-400 p-2">{att.function || ''}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <p className="mb-2 italic text-sm">
          Une réunion a été faite en présence des membres ci-dessus. Cette réunion a eu pour objet : 
          <span className="font-semibold underline ml-1">{data.objective || 'Discussion générale'}</span>
        </p>
        <p className="mb-4 text-sm">Ci-dessous l'état des lieux pour un suivi des actions :</p>

        <div className="mb-6">
          <h3 className="font-bold underline mb-2">Rapport sur les résultats de réunion :</h3>
          <div className="min-h-[100px] border border-slate-200 p-4 rounded bg-slate-50/50 whitespace-pre-wrap">
            {data.report || 'Aucun rapport généré.'}
          </div>
        </div>

        {/* Action Items Table */}
        <div>
          <h3 className="font-bold underline mb-2">A faire :</h3>
          <table className="w-full border-collapse border border-slate-400 text-[9pt]">
            <thead className="bg-[#7fb442] text-white">
              <tr>
                <th className="border border-slate-400 p-2">Actions à faires</th>
                <th className="border border-slate-400 p-2">Responsable de réalisation</th>
                <th className="border border-slate-400 p-2">Echéance</th>
                <th className="border border-slate-400 p-2">Suivi de réalisation</th>
              </tr>
            </thead>
            <tbody>
              {(data.tasks || [{}, {}, {}, {}]).map((task: any, idx: number) => (
                <tr key={idx} className="h-10">
                  <td className="border border-slate-400 p-2">{task.task || ''}</td>
                  <td className="border border-slate-400 p-2">{task.owner || ''}</td>
                  <td className="border border-slate-400 p-2">{task.deadline || ''}</td>
                  <td className="border border-slate-400 p-2 text-center">{task.status || ''}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="mt-8 pt-4 border-t border-slate-200 text-center text-[8pt] text-slate-400 italic">
          Ce document est la propriété de l'hôtel Golden Carthage Tunis. Toute reproduction du document est prohibée.
        </div>
      </div>
    );
  };

  const isWordTemplateMode = templateMode === 'word_template';
  const isPVMode = templateMode === 'pv_meeting';

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-indigo-100 selection:text-indigo-800">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 no-print">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
              Gemini Transcribe
            </h1>
          </div>
          <div className="text-xs font-medium px-2.5 py-1 bg-indigo-50 text-indigo-700 rounded-full border border-indigo-100">
            Powered by Gemini 2.5 Flash
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-12 sm:px-6 lg:px-8">
        <div className="space-y-12">

          <section className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden no-print">
             <div className="p-6 pb-0">
               <TemplateSelector 
                  template={template} 
                  onTemplateChange={setTemplate}
                  context={context}
                  onContextChange={setContext}
                  mode={templateMode}
                  onModeChange={setTemplateMode}
                  wordTemplateName={wordTemplateName}
                  onWordTemplateUpload={handleWordTemplateUpload}
               />
             </div>
             <div className="p-1 border-t border-slate-100">
               <AudioRecorder
                currentState={state.status}
                onTranscriptionStart={handleStart}
                onTranscriptionComplete={handleComplete}
                onTranscriptionError={handleError}
                template={template || (templateMode === 'pv_meeting' ? PV_TEMPLATE_INSTRUCTIONS : '')}
                context={context}
                isJsonMode={isWordTemplateMode || isPVMode}
              />
             </div>
          </section>

          {state.status === 'error' && (
            <div className="bg-red-50 border border-red-200 rounded-2xl p-6 flex items-start space-x-4 animate-fade-in no-print">
              <div className="flex-shrink-0"><svg className="h-6 w-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></div>
              <div className="flex-1">
                <h3 className="text-sm font-medium text-red-800">Process Failed</h3>
                <p className="mt-1 text-sm text-red-700">{state.error}</p>
                <button onClick={reset} className="mt-3 text-sm font-medium text-red-600 hover:text-red-500">Try Again &rarr;</button>
              </div>
            </div>
          )}

          {state.status === 'success' && (
            <section className="space-y-4 animate-fade-in-up">
              <div className="flex items-center justify-between no-print flex-wrap gap-2">
                <h2 className="text-lg font-semibold text-slate-800">
                  {state.jsonResult ? 'Professional Document' : 'Transcribed Notes'}
                </h2>
                <div className="flex space-x-2">
                   <button onClick={handleExportWord} className="flex items-center space-x-2 px-3 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors shadow-sm text-sm font-medium">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                    <span>{isWordTemplateMode ? 'Download Filled Word' : 'Export Word'}</span>
                  </button>
                  <button onClick={handlePrintPDF} className="flex items-center space-x-2 px-3 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg transition-colors shadow-sm text-sm font-medium">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    <span>Export PDF</span>
                  </button>
                  <button onClick={reset} className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="New entry"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
                </div>
              </div>

              <div id="results-container" className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
                {isPVMode && state.jsonResult ? (
                   renderPVMeeting(state.jsonResult)
                ) : state.jsonResult ? (
                  <div className="p-8"><pre className="text-indigo-700 font-mono text-sm whitespace-pre-wrap">{JSON.stringify(state.jsonResult, null, 2)}</pre></div>
                ) : (
                  <div className="p-8 prose prose-slate max-w-none" dangerouslySetInnerHTML={getMarkdownHtml(state.text)} />
                )}
              </div>
            </section>
          )}
        </div>
      </main>
      <footer className="py-8 text-center text-slate-400 text-sm no-print">
        <p>&copy; {new Date().getFullYear()} Golden Carthage Meeting Manager</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';

export interface TemplateSelectorProps {
  template: string;
  onTemplateChange: (template: string) => void;
  context: string;
  onContextChange: (context: string) => void;
  mode: 'general' | 'word_template' | 'pv_meeting';
  onModeChange: (mode: 'general' | 'word_template' | 'pv_meeting') => void;
  wordTemplateName: string | null;
  onWordTemplateUpload: (file: File) => void;
}

export const PV_TEMPLATE_INSTRUCTIONS = `Extract meeting details into a JSON object matching these specific keys:
- pv_num: The meeting number or ID.
- date: The date of the meeting.
- team: The team or department involved (e.g., "EQUIPE concernée").
- agenda: The meeting agenda (e.g., "Ordre du jour").
- attendees: An array of objects with {name, function}.
- objective: The main goal of the meeting (Objet).
- report: A detailed summary of results/discussion (Rapport sur les résultats).
- tasks: An array of objects with {task, owner, deadline, status} for action items.

Return ONLY the JSON object.`;

export const WORD_TEMPLATE_INSTRUCTIONS = `Extract information to fill a Word document template. Return a valid JSON object matching the placeholders in your file. If no specific placeholders are detected, provide a general meeting summary in JSON format.`;

export const TemplateSelector: React.FC<TemplateSelectorProps> = ({
  template,
  onTemplateChange,
  context,
  onContextChange,
  mode,
  onModeChange,
  wordTemplateName,
  onWordTemplateUpload
}) => {
  const wordInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    if (mode === 'pv_meeting' && !template) {
       onTemplateChange(PV_TEMPLATE_INSTRUCTIONS);
    }
  }, [mode]);

  const handleModeChange = (newMode: 'general' | 'word_template' | 'pv_meeting') => {
    onModeChange(newMode);
    if (newMode === 'general') {
      onTemplateChange('');
    } else if (newMode === 'pv_meeting') {
      onTemplateChange(PV_TEMPLATE_INSTRUCTIONS);
    } else if (newMode === 'word_template') {
       if (!template || template === PV_TEMPLATE_INSTRUCTIONS) {
         onTemplateChange(WORD_TEMPLATE_INSTRUCTIONS);
       }
    }
  };

  const handleWordFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) onWordTemplateUpload(file);
  };

  const onDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const onDragLeave = () => setIsDragging(false);
  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file && (file.name.endsWith('.docx') || file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document')) {
      onWordTemplateUpload(file);
    } else {
      alert("Please upload a valid .docx Word file.");
    }
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 mb-6 shadow-sm animate-fade-in divide-y divide-slate-100">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 pb-4">
        <div>
           <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider">Document Type</h3>
           <p className="text-xs text-slate-500">Select the desired output format</p>
        </div>
        <div className="flex flex-wrap gap-1 bg-slate-100 rounded-lg p-1">
          <button onClick={() => handleModeChange('pv_meeting')} className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${mode === 'pv_meeting' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>PV de réunion</button>
          <button onClick={() => handleModeChange('general')} className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${mode === 'general' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>Simple Note</button>
          <button onClick={() => handleModeChange('word_template')} className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${mode === 'word_template' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>Word .docx</button>
        </div>
      </div>

      <div className="py-4">
        {mode === 'word_template' ? (
          <div className="space-y-4 animate-fade-in">
            <div onDragOver={onDragOver} onDragLeave={onDragLeave} onDrop={onDrop} className={`relative group border-2 border-dashed rounded-2xl p-6 transition-all duration-200 text-center ${isDragging ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' : 'border-indigo-200 bg-indigo-50/50 hover:bg-indigo-50'}`}>
              <div className="flex flex-col items-center">
                <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-3 transition-colors ${isDragging ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm'}`}>
                  <svg xmlns="http://www.w3.org/2000/svg" className={`h-7 w-7 ${isDragging ? 'animate-bounce' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                </div>
                <h4 className="text-sm font-bold text-indigo-900">{wordTemplateName ? `Template: ${wordTemplateName}` : 'Upload Word Design'}</h4>
                <p className="text-xs text-indigo-600/80 mb-4">Drag and drop your .docx file here to automate it.</p>
                <button onClick={() => wordInputRef.current?.click()} className="px-5 py-2 bg-white border border-indigo-200 text-indigo-700 rounded-xl text-sm font-semibold hover:bg-indigo-100 transition-colors shadow-sm">Select File</button>
                <input type="file" ref={wordInputRef} className="hidden" accept=".docx" onChange={handleWordFileUpload} />
              </div>
            </div>
          </div>
        ) : mode === 'pv_meeting' ? (
          <div className="bg-green-50/50 p-4 rounded-2xl border border-green-100 animate-fade-in">
            <h4 className="text-sm font-bold text-green-900 mb-1">Professional PV Mode Active</h4>
            <p className="text-xs text-green-700 mb-4">AI will structure the audio into the official PV de réunion format with green headers and data tables.</p>
            <textarea
              value={template}
              onChange={(e) => onTemplateChange(e.target.value)}
              className="w-full h-24 p-3 text-xs font-mono text-slate-700 bg-white border border-green-200 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
            />
          </div>
        ) : (
          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 flex flex-col items-center text-center">
            <h4 className="text-sm font-bold text-slate-800">Simple Note Mode</h4>
            <p className="text-xs text-slate-500 mt-1">AI will summarize the content in clean Markdown with headers and bullets.</p>
          </div>
        )}
      </div>

      <div className="pt-4">
        <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider mb-2">Context (Names & roles)</h3>
        <textarea
          value={context}
          onChange={(e) => onContextChange(e.target.value)}
          placeholder="E.g. Sara is BD. Tarek is PDG. Meeting about Project X."
          className="w-full h-24 p-3 text-sm font-sans text-slate-700 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none shadow-inner"
        />
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not set");
  }
  return new GoogleGenAI({ apiKey });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

const buildSystemInstruction = (context?: string) => {
  let instruction = "You are an expert transcriber and professional secretary for Golden Carthage. Your task is to extract meeting data into structured formats.";
  if (context && context.trim().length > 0) {
    instruction += `\n\nCONTEXT & VOCABULARY:\n${context}`;
  }
  return instruction;
};

const buildPrompt = (template: string, isJsonMode: boolean, language: string) => {
  let prompt = "";
  if (isJsonMode) {
    prompt = `Analyze the provided audio content and extract information into the requested JSON fields.

INSTRUCTIONS:
${template}

IMPORTANT:
- If two audio files are provided, the first is the MAIN MEETING and the second is the METADATA (Attendees, Date, etc.).
- Combine info from both to fill the fields accurately.
- Return ONLY valid JSON.
- Do not include markdown formatting like \`\`\`json.`;
  } else {
    prompt = "Analyze the provided content and create structured notes in Markdown.";
  }

  if (language && language !== 'Auto-detect') {
    prompt += `\n\nIMPORTANT: The language is ${language}.`;
  }
  return prompt;
};

export const processText = async (
  inputText: string,
  language: string = 'Auto-detect',
  template?: string,
  context?: string,
  isJsonMode: boolean = false
): Promise<{ text: string, json?: any }> => {
  try {
    const ai = getGeminiClient();
    const systemInstruction = buildSystemInstruction(context);
    const prompt = buildPrompt(template || "", isJsonMode, language);

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Content:\n${inputText}\n\nInstruction:\n${prompt}`,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: isJsonMode ? 'application/json' : 'text/plain'
      }
    });

    const text = response.text || "";
    if (isJsonMode) {
      try {
        const json = JSON.parse(text);
        return { text: JSON.stringify(json, null, 2), json };
      } catch (e) {
        return { text };
      }
    }
    return { text };
  } catch (error: any) {
    throw new Error(error.message || "Failed to process text.");
  }
};

export const transcribeAudio = async (
  audioBlobs: Blob | Blob[], 
  language: string = 'Auto-detect', 
  template?: string,
  context?: string,
  isJsonMode: boolean = false
): Promise<{ text: string, json?: any }> => {
  try {
    const ai = getGeminiClient();
    const blobs = Array.isArray(audioBlobs) ? audioBlobs : [audioBlobs];

    const parts = await Promise.all(blobs.map(async (blob, index) => {
      const base64 = await blobToBase64(blob);
      return {
        inlineData: {
          mimeType: blob.type || 'audio/webm',
          data: base64
        }
      };
    }));

    const systemInstruction = buildSystemInstruction(context);
    const prompt = buildPrompt(template || "", isJsonMode, language);

    // Add text instructions as the last part
    parts.push({ text: prompt } as any);

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: parts as any },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: isJsonMode ? 'application/json' : 'text/plain'
      }
    });

    const text = response.text || "";
    if (isJsonMode) {
      try {
        const json = JSON.parse(text);
        return { text: JSON.stringify(json, null, 2), json };
      } catch (e) {
        return { text };
      }
    }
    return { text };
  } catch (error: any) {
    throw new Error(error.message || "Failed to transcribe audio.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { TranscriptionState } from '../types';

interface MediaInputProps {
  onTranscriptionStart: () => void;
  onTranscriptionComplete: (text: string, json?: any) => void;
  onTranscriptionError: (error: string) => void;
  currentState: TranscriptionState['status'];
  template: string;
  context: string;
  isJsonMode: boolean;
}

const LANGUAGES = [
  'Auto-detect',
  'Tunisian Dialect',
  'Saudi Dialect',
  'English',
  'French',
  'Arabic'
];

export const AudioRecorder: React.FC<MediaInputProps> = ({
  onTranscriptionStart,
  onTranscriptionComplete,
  onTranscriptionError,
  currentState,
  template,
  context,
  isJsonMode
}) => {
  const [mode, setMode] = useState<'record' | 'upload' | 'text'>('record');
  const [step, setStep] = useState<1 | 2>(1); // Step 1: Meeting, Step 2: Metadata
  const [blobs, setBlobs] = useState<Blob[]>([]);

  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [selectedLanguage, setSelectedLanguage] = useState('Auto-detect');
  const [manualText, setManualText] = useState('');

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const timerRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (mediaRecorderRef.current?.state === 'recording') mediaRecorderRef.current.stop();
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        stream.getTracks().forEach(track => track.stop());

        const newBlobs = [...blobs, blob];
        setBlobs(newBlobs);

        if (step === 1) {
          setStep(2);
        } else {
          executeTranscription(newBlobs);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
      setDuration(0);
      timerRef.current = window.setInterval(() => setDuration(prev => prev + 1), 1000);
    } catch (err) {
      onTranscriptionError("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const executeTranscription = async (targetBlobs: Blob[]) => {
    onTranscriptionStart();
    try {
      const { transcribeAudio } = await import('../services/geminiService');
      const result = await transcribeAudio(targetBlobs, selectedLanguage, template, context, isJsonMode);
      onTranscriptionComplete(result.text, result.json);
      // Reset for next time
      setBlobs([]);
      setStep(1);
    } catch (error: any) {
      onTranscriptionError(error.message);
      setBlobs([]);
      setStep(1);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) executeTranscription([file]);
  };

  const handleProcessManualText = async () => {
    if (!manualText.trim()) return;
    onTranscriptionStart();
    try {
      const { processText } = await import('../services/geminiService');
      const result = await processText(manualText, selectedLanguage, template, context, isJsonMode);
      onTranscriptionComplete(result.text, result.json);
    } catch (error: any) {
      onTranscriptionError(error.message);
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isProcessing = currentState === 'processing';

  return (
    <div className="flex flex-col items-center space-y-4 w-full max-w-xl mx-auto p-4 sm:p-6">

      {!isRecording && !isProcessing && (
        <div className="w-full space-y-4 animate-fade-in">
          <div className="flex p-1 bg-slate-100 rounded-xl">
            <button onClick={() => setMode('record')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${mode === 'record' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Record</button>
            <button onClick={() => setMode('upload')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${mode === 'upload' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Upload</button>
            <button onClick={() => setMode('text')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${mode === 'text' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Text</button>
          </div>

          <div className="flex items-center justify-center">
            <select
              value={selectedLanguage}
              onChange={(e) => setSelectedLanguage(e.target.value)}
              className="px-3 py-1.5 text-xs border border-slate-200 rounded-lg bg-white text-slate-700 outline-none"
            >
              {LANGUAGES.map((lang) => <option key={lang} value={lang}>{lang}</option>)}
            </select>
          </div>
        </div>
      )}

      <div className="w-full min-h-[180px] flex items-center justify-center">
        {mode === 'record' && (
          <div className="flex flex-col items-center space-y-4 w-full">
            {/* Step Indicator */}
            {!isProcessing && (
              <div className="flex items-center gap-2 mb-2">
                <div className={`w-2 h-2 rounded-full ${step >= 1 ? 'bg-indigo-600' : 'bg-slate-200'}`}></div>
                <div className={`w-8 h-1 rounded-full ${step >= 2 ? 'bg-indigo-600' : 'bg-slate-200'}`}></div>
                <div className={`w-2 h-2 rounded-full ${step >= 2 ? 'bg-indigo-600' : 'bg-slate-200'}`}></div>
              </div>
            )}

            <div className={`w-32 h-32 rounded-full border-4 flex flex-col items-center justify-center transition-all ${isRecording ? 'border-red-500 bg-red-50 scale-105' : 'border-slate-100 bg-white shadow-inner'}`}>
              {isRecording ? (
                <div className="animate-pulse text-red-600 font-mono font-bold text-lg">{formatDuration(duration)}</div>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-200" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                </svg>
              )}
            </div>

            {!isRecording && !isProcessing && (
              <div className="text-center space-y-3">
                <h4 className="font-bold text-slate-800">
                  {step === 1 ? "Step 1: Record Meeting content" : "Step 2: Record details (Attendees, Date, Visa...)"}
                </h4>
                <button 
                  onClick={startRecording} 
                  className={`px-8 py-3 rounded-2xl shadow-lg font-bold flex items-center gap-2 transition-transform active:scale-95 ${step === 1 ? 'bg-indigo-600 hover:bg-indigo-700 text-white' : 'bg-green-600 hover:bg-green-700 text-white'}`}
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 18.5a6.5 6.5 0 100-13 6.5 6.5 0 000 13z" /></svg>
                  {step === 1 ? "Start Meeting Audio" : "Record Metadata Audio"}
                </button>
                {step === 2 && (
                  <button onClick={() => setStep(1)} className="text-xs text-slate-400 hover:text-slate-600 underline">Back to step 1</button>
                )}
              </div>
            )}

            {isRecording && (
              <button onClick={stopRecording} className="px-8 py-3 bg-white border-2 border-red-500 text-red-600 rounded-2xl shadow-md font-bold flex items-center gap-2 active:scale-95">
                <div className="w-3 h-3 bg-red-600 rounded-sm"></div>
                Finish {step === 1 ? "Meeting Content" : "Recording Metadata"}
              </button>
            )}
          </div>
        )}

        {mode === 'upload' && !isProcessing && (
          <div className="w-full animate-fade-in px-4">
            <div onClick={() => fileInputRef.current?.click()} className="w-full h-32 border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50 flex flex-col items-center justify-center cursor-pointer hover:border-indigo-300 transition-all">
              <input type="file" ref={fileInputRef} className="hidden" accept="audio/*" onChange={handleFileUpload} />
              <p className="text-slate-800 font-bold text-sm">Upload Single Meeting File</p>
              <p className="text-slate-400 text-[10px] mt-1">MP3, WAV (Max 10MB)</p>
            </div>
          </div>
        )}

        {mode === 'text' && !isProcessing && (
          <div className="w-full space-y-3 animate-fade-in px-4">
            <textarea
              value={manualText}
              onChange={(e) => setManualText(e.target.value)}
              placeholder="Paste meeting transcript here..."
              className="w-full h-32 p-3 text-sm font-sans text-slate-700 bg-white border border-slate-200 rounded-xl focus:ring-1 focus:ring-indigo-500 outline-none resize-none shadow-inner"
            />
            <button onClick={handleProcessManualText} disabled={!manualText.trim()} className="w-full py-3 bg-indigo-600 text-white rounded-xl shadow-md font-bold text-sm disabled:opacity-50">Process Text</button>
          </div>
        )}

        {isProcessing && (
          <div className="flex flex-col items-center justify-center animate-fade-in">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="mt-4 font-bold text-indigo-900">Structuring your PV...</p>
            <p className="text-slate-500 text-xs">Combining meeting audio & metadata.</p>
          </div>
        )}
      </div>
    </div>
  );
};

