                ) : (
                  <div className="p-8 prose prose-slate max-w-none" dangerouslySetInnerHTML={getMarkdownHtml(state.text)} />
                )}
              </div>
            </section>
          )}
        </div>
      </main>
      <footer className="py-8 text-center text-slate-400 text-sm no-print">
        <p>&copy; {new Date().getFullYear()} Golden Carthage Meeting Manager</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';

export interface TemplateSelectorProps {
  template: string;
  onTemplateChange: (template: string) => void;
  context: string;
  onContextChange: (context: string) => void;
  mode: 'general' | 'word_template' | 'pv_meeting';
  onModeChange: (mode: 'general' | 'word_template' | 'pv_meeting') => void;
  wordTemplateName: string | null;
  onWordTemplateUpload: (file: File) => void;
  logoUrl: string | null;
  onLogoChange: (url: string | null) => void;
}

export const PV_TEMPLATE_INSTRUCTIONS = `Extract meeting details into a JSON object matching these specific keys:
- pv_num: The meeting number or ID.
- date: The date of the meeting.
- team: The team or department involved (e.g., "EQUIPE concernée").
- agenda: The meeting agenda (e.g., "Ordre du jour").
- attendees: An array of objects with {name, function}.
- objective: The main goal of the meeting (Objet).
- report: A detailed summary of results/discussion (Rapport sur les résultats).
- tasks: An array of objects with {task, owner, deadline, status} for action items.

Return ONLY the JSON object.`;

export const WORD_TEMPLATE_INSTRUCTIONS = `Extract information to fill a Word document template. Return a valid JSON object matching the placeholders in your file. If no specific placeholders are detected, provide a general meeting summary in JSON format.`;

export const TemplateSelector: React.FC<TemplateSelectorProps> = ({
  template,
  onTemplateChange,
  context,
  onContextChange,
  mode,
  onModeChange,
  wordTemplateName,
  onWordTemplateUpload,
  logoUrl,
  onLogoChange
}) => {
  const wordInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isDraggingLogo, setIsDraggingLogo] = useState(false);

  useEffect(() => {
    if (mode === 'pv_meeting' && !template) {
       onTemplateChange(PV_TEMPLATE_INSTRUCTIONS);
    }
  }, [mode]);

  const handleModeChange = (newMode: 'general' | 'word_template' | 'pv_meeting') => {
    onModeChange(newMode);
    if (newMode === 'general') {
      onTemplateChange('');
    } else if (newMode === 'pv_meeting') {
      onTemplateChange(PV_TEMPLATE_INSTRUCTIONS);
    } else if (newMode === 'word_template') {
       if (!template || template === PV_TEMPLATE_INSTRUCTIONS) {
         onTemplateChange(WORD_TEMPLATE_INSTRUCTIONS);
       }
    }
  };

  const handleWordFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) onWordTemplateUpload(file);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        if (ev.target?.result) onLogoChange(ev.target.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const onDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const onDragLeave = () => setIsDragging(false);
  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file && (file.name.endsWith('.docx') || file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document')) {
      onWordTemplateUpload(file);
    } else {
      alert("Please upload a valid .docx Word file.");
    }
  };

  const onDragOverLogo = (e: React.DragEvent) => { e.preventDefault(); setIsDraggingLogo(true); };
  const onDragLeaveLogo = () => setIsDraggingLogo(false);
  const onDropLogo = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDraggingLogo(false);
    const file = e.dataTransfer.files[0];
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        if (ev.target?.result) onLogoChange(ev.target.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 mb-6 shadow-sm animate-fade-in divide-y divide-slate-100">

      {/* Document Type Selector */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 pb-4">
        <div>
           <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider">Document Type</h3>
           <p className="text-xs text-slate-500">Select the desired output format</p>
        </div>
        <div className="flex flex-wrap gap-1 bg-slate-100 rounded-lg p-1">
          <button onClick={() => handleModeChange('pv_meeting')} className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${mode === 'pv_meeting' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>PV de réunion</button>
          <button onClick={() => handleModeChange('general')} className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${mode === 'general' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>Simple Note</button>
          <button onClick={() => handleModeChange('word_template')} className={`px-4 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${mode === 'word_template' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>Word .docx</button>
        </div>
      </div>

      {/* Template & Logo Config */}
      <div className="py-4 space-y-4">
        {mode === 'word_template' ? (
          <div className="space-y-4 animate-fade-in">
            <div onDragOver={onDragOver} onDragLeave={onDragLeave} onDrop={onDrop} className={`relative group border-2 border-dashed rounded-2xl p-6 transition-all duration-200 text-center ${isDragging ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' : 'border-indigo-200 bg-indigo-50/50 hover:bg-indigo-50'}`}>
              <div className="flex flex-col items-center">
                <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-3 transition-colors ${isDragging ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm'}`}>
                  <svg xmlns="http://www.w3.org/2000/svg" className={`h-7 w-7 ${isDragging ? 'animate-bounce' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                </div>
                <h4 className="text-sm font-bold text-indigo-900">{wordTemplateName ? `Template: ${wordTemplateName}` : 'Upload Word Design'}</h4>
                <p className="text-xs text-indigo-600/80 mb-4">Drag and drop your .docx file here to automate it.</p>
                <button onClick={() => wordInputRef.current?.click()} className="px-5 py-2 bg-white border border-indigo-200 text-indigo-700 rounded-xl text-sm font-semibold hover:bg-indigo-100 transition-colors shadow-sm">Select File</button>
                <input type="file" ref={wordInputRef} className="hidden" accept=".docx" onChange={handleWordFileUpload} />
              </div>
            </div>
          </div>
        ) : mode === 'pv_meeting' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-fade-in">
            {/* Logo Upload Section */}
            <div 
              onDragOver={onDragOverLogo} 
              onDragLeave={onDragLeaveLogo} 
              onDrop={onDropLogo}
              className={`border-2 border-dashed rounded-2xl p-4 flex flex-col items-center justify-center min-h-[140px] transition-all cursor-pointer ${isDraggingLogo ? 'border-amber-500 bg-amber-50' : 'border-slate-200 bg-slate-50 hover:border-amber-200 hover:bg-white'}`}
              onClick={() => logoInputRef.current?.click()}
            >
              {logoUrl ? (
                <div className="relative group w-full h-full flex items-center justify-center">
                  <img src={logoUrl} alt="Preview" className="max-h-24 object-contain" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded-xl transition-opacity">
                    <span className="text-white text-xs font-bold">Click or drop to change logo</span>
                  </div>
                </div>
              ) : (
                <div className="flex flex-col items-center text-slate-400">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                  <p className="text-[10px] font-bold uppercase tracking-tight">Upload Hotel Logo</p>
                  <p className="text-[9px] mt-1">PNG, JPG, SVG (Drag & Drop)</p>
                </div>
              )}
              <input type="file" ref={logoInputRef} className="hidden" accept="image/*" onChange={handleLogoUpload} />
            </div>

            {/* Instruction Editor */}
            <div className="bg-green-50/30 p-4 rounded-2xl border border-green-100">
              <h4 className="text-[10px] font-bold text-green-800 uppercase mb-2">Extraction Settings</h4>
              <textarea
                value={template}
                onChange={(e) => onTemplateChange(e.target.value)}
                className="w-full h-24 p-2 text-[10px] font-mono text-slate-700 bg-white border border-green-100 rounded-lg focus:ring-1 focus:ring-green-500 outline-none"
              />
            </div>
          </div>
        ) : (
          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 flex flex-col items-center text-center">
            <h4 className="text-sm font-bold text-slate-800">Simple Note Mode</h4>
            <p className="text-xs text-slate-500 mt-1">AI will summarize the content in clean Markdown with headers and bullets.</p>
          </div>
        )}
      </div>

      {/* Context / Vocabulary Section */}
      <div className="pt-4">
        <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider mb-2">Context (Names & roles)</h3>
        <textarea
          value={context}
          onChange={(e) => onContextChange(e.target.value)}
          placeholder="E.g. Sara is BD. Tarek is PDG. Meeting about Project X."
          className="w-full h-24 p-3 text-sm font-sans text-slate-700 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none shadow-inner"
        />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AudioRecorder } from './components/AudioRecorder';
import { TemplateSelector, WORD_TEMPLATE_INSTRUCTIONS, PV_TEMPLATE_INSTRUCTIONS } from './components/TemplateSelector';
import { TranscriptionState } from './types';

// Declare globals for libraries loaded via script tags
declare const marked: any;
declare const PizZip: any;
declare const docxtemplater: any;
declare const saveAs: any;

const App: React.FC = () => {
  const [state, setState] = useState<TranscriptionState>({
    status: 'idle',
    text: null,
    error: null,
    jsonResult: null
  });
  const [template, setTemplate] = useState<string>('');
  const [context, setContext] = useState<string>("Sara is in the BD (Business Development) department.\nTarek is the PDG (CEO).\nActivity: We presented 4 automations and 9 web applications.");
  const [templateMode, setTemplateMode] = useState<'general' | 'word_template' | 'pv_meeting'>('pv_meeting');
  const [wordTemplateFile, setWordTemplateFile] = useState<ArrayBuffer | null>(null);
  const [wordTemplateName, setWordTemplateName] = useState<string | null>(null);
  const [logoUrl, setLogoUrl] = useState<string | null>(null);

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string, json?: any) => {
    setState({ status: 'success', text, jsonResult: json, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error, jsonResult: null });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null, jsonResult: null });
  };

  const handleWordTemplateUpload = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        const arrayBuffer = e.target.result as ArrayBuffer;
        setWordTemplateFile(arrayBuffer);
        setWordTemplateName(file.name);

        try {
          const zip = new PizZip(arrayBuffer);
          let detectedPlaceholders: string[] = [];
          if (zip.files['word/document.xml']) {
             const docXml = zip.files['word/document.xml'].asText();
             const rawMatches = docXml.match(/\{[a-zA-Z0-9_]+\}/g);
             if (rawMatches) detectedPlaceholders.push(...rawMatches);
          }

          if (detectedPlaceholders.length > 0) {
            const vars = detectedPlaceholders.map((m: string) => m.replace(/[\{\}]/g, ''));
            const uniqueVars = [...new Set(vars)];
            const newInstruction = `The uploaded Word template contains placeholders. Extract:\n${uniqueVars.map(v => `- ${v}`).join('\n')}\nReturn valid JSON.`;
            setTemplate(newInstruction);
          } else {
             setTemplate(WORD_TEMPLATE_INSTRUCTIONS);
          }
        } catch (err) {
           setTemplate(WORD_TEMPLATE_INSTRUCTIONS);
        }
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const generatePVWordHtml = (data: any) => {
    const attendeesHtml = (data.attendees && data.attendees.length > 0 ? data.attendees : [{}, {}, {}])
      .map((att: any) => `
        <tr style="height: 30px;">
          <td style="border: 1px solid #94a3b8; padding: 8px;">${att.name || ''}</td>
          <td style="border: 1px solid #94a3b8; padding: 8px; color: #94a3b8; font-size: 8pt; font-style: italic;">Electronique</td>
          <td style="border: 1px solid #94a3b8; padding: 8px;">${att.function || ''}</td>
        </tr>
      `).join('');

    const tasksHtml = (data.tasks && data.tasks.length > 0 ? data.tasks : [{}, {}, {}, {}])
      .map((task: any) => `
        <tr style="height: 40px;">
          <td style="border: 1px solid #94a3b8; padding: 8px;">${task.task || ''}</td>
          <td style="border: 1px solid #94a3b8; padding: 8px;">${task.owner || ''}</td>
          <td style="border: 1px solid #94a3b8; padding: 8px;">${task.deadline || ''}</td>
          <td style="border: 1px solid #94a3b8; padding: 8px; text-align: center;">${task.status || ''}</td>
        </tr>
      `).join('');

    const logoHtml = logoUrl 
      ? `<img src="${logoUrl}" style="max-height: 80px; width: auto;" />`
      : `<div style="color: #C5A048; text-align: center;">
          <div style="font-weight: bold; font-size: 14pt; letter-spacing: 2px;">GOLDEN CARTHAGE</div>
          <div style="font-size: 8pt;">Hotel & Residence Tunis</div>
         </div>`;

    return `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>PV de Réunion</title>
      <style>
        body { font-family: 'Calibri', 'Arial', sans-serif; font-size: 11pt; color: #1e293b; }
        table { border-collapse: collapse; width: 100%; }
        .header-table td { border: 1px solid #94a3b8; padding: 10px; }
        .green-bg { background-color: #7fb442; color: white; font-weight: bold; }
        .label { width: 150px; }
      </style>
      </head>
      <body>
        <!-- Header Section -->
        <table class="header-table" style="margin-bottom: 20px;">
          <tr>
            <td style="width: 33%; text-align: center; vertical-align: middle;">${logoHtml}</td>
            <td style="width: 33%; text-align: center; vertical-align: middle; font-size: 16pt; font-weight: bold; font-style: italic; text-transform: uppercase;">PV de réunion</td>
            <td style="width: 33%; font-size: 8pt; text-transform: uppercase;">
              <div style="border-bottom: 1px solid #94a3b8; padding: 2px;">Réf: ${data.ref || 'QUA-ENR-03'}</div>
              <div style="border-bottom: 1px solid #94a3b8; padding: 2px;">Version: ${data.version || '00'}</div>
              <div style="border-bottom: 1px solid #94a3b8; padding: 2px;">Date: ${data.date || new Date().toLocaleDateString('fr-FR')}</div>
              <div style="padding: 2px;">Page: 1 sur 1</div>
            </td>
          </tr>
        </table>

        <!-- PV Number Bar -->
        <div style="background-color: #7fb442; color: white; font-weight: bold; padding: 5px 10px; border: 1px solid #94a3b8; margin-bottom: 5px;">
          N° de PV : <span style="font-weight: normal;">${data.pv_num || '________________'}</span>
        </div>

        <!-- Info Grid -->
        <table style="margin-bottom: 20px; border: 1px solid #94a3b8;">
          <tr>
            <td class="green-bg label" style="padding: 8px;">Date:</td>
            <td style="border: 1px solid #94a3b8; padding: 8px;">${data.date || '________________'}</td>
          </tr>
          <tr>
            <td class="green-bg label" style="padding: 8px;">EQUIPE concernée :</td>
            <td style="border: 1px solid #94a3b8; padding: 8px;">${data.team || '________________'}</td>
          </tr>
          <tr>
            <td class="green-bg label" style="padding: 8px;">Ordre du jour :</td>
            <td style="border: 1px solid #94a3b8; padding: 8px;">${data.agenda || '________________'}</td>
          </tr>
        </table>

        <!-- Attendees -->
        <div style="background-color: #7fb442; color: white; font-weight: bold; text-align: center; padding: 5px; border: 1px solid #94a3b8; border-bottom: none;">Présents</div>
        <table style="margin-bottom: 20px; border: 1px solid #94a3b8;">
          <tr style="background-color: #f8fafc; font-weight: bold;">
            <td style="border: 1px solid #94a3b8; padding: 8px; width: 33%;">Nom et prénom</td>
            <td style="border: 1px solid #94a3b8; padding: 8px; width: 33%;">Visa</td>
            <td style="border: 1px solid #94a3b8; padding: 8px; width: 33%;">Fonction</td>
          </tr>
          ${attendeesHtml}
        </table>

        <p style="font-style: italic; font-size: 10pt; margin-bottom: 5px;">
          Une réunion a été faite en présence des membres ci-dessus. Cette réunion a eu pour objet : 
          <span style="font-weight: bold; text-decoration: underline;">${data.objective || 'Discussion générale'}</span>
        </p>
        <p style="font-size: 10pt; margin-bottom: 20px;">Ci-dessous l'état des lieux pour un suivi des actions :</p>

        <!-- Report Body -->
        <div style="margin-bottom: 20px;">
          <h3 style="font-weight: bold; text-decoration: underline; font-size: 12pt;">Rapport sur les résultats de réunion :</h3>
          <div style="border: 1px solid #e2e8f0; padding: 15px; background-color: #fdfdfd; min-height: 100px;">
            ${data.report ? data.report.replace(/\n/g, '<br/>') : 'Aucun rapport généré.'}
          </div>
        </div>

        <!-- Action Items -->
        <h3 style="font-weight: bold; text-decoration: underline; font-size: 12pt; margin-bottom: 10px;">A faire :</h3>
        <table style="border: 1px solid #94a3b8;">
          <tr class="green-bg" style="text-align: center;">
            <td style="border: 1px solid #94a3b8; padding: 8px;">Actions à faires</td>
            <td style="border: 1px solid #94a3b8; padding: 8px;">Responsable de réalisation</td>
            <td style="border: 1px solid #94a3b8; padding: 8px;">Echéance</td>
            <td style="border: 1px solid #94a3b8; padding: 8px;">Suivi de réalisation</td>
          </tr>
          ${tasksHtml}
        </table>

        <div style="margin-top: 40px; border-top: 1px solid #e2e8f0; padding-top: 10px; text-align: center; font-size: 8pt; color: #94a3b8; font-style: italic;">
          Ce document est la propriété de l'hôtel Golden Carthage Tunis. Toute reproduction du document est prohibée.
        </div>
      </body>
      </html>
    `;
  };

  const handleExportWord = () => {
    if (state.jsonResult && wordTemplateFile && templateMode === 'word_template') {
       try {
         const zip = new PizZip(wordTemplateFile);
         const doc = new docxtemplater(zip, {
            paragraphLoop: true,
            linebreaks: true,
            nullGetter: () => ""
         });
         doc.render(state.jsonResult);
         const out = doc.getZip().generate({
            type: "blob",
            mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
         });
         saveAs(out, `filled_${wordTemplateName || 'document.docx'}`);
       } catch (error: any) {
          alert("Error generating Word document.");
       }
       return;
    }

    if (templateMode === 'pv_meeting' && state.jsonResult) {
      const sourceHTML = generatePVWordHtml(state.jsonResult);
      const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
      const fileDownload = document.createElement("a");
      fileDownload.href = source;
      fileDownload.download = `PV_Reunion_${state.jsonResult.date || 'Export'}.doc`;
      fileDownload.click();
      return;
    }

    if (!state.text) return;
    let htmlContent = typeof marked !== 'undefined' ? marked.parse(state.text) : `<pre>${state.text}</pre>`;
    const header = "<html><head><meta charset='utf-8'></head><body>";
    const sourceHTML = header + htmlContent + "</body></html>";
    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    fileDownload.href = source;
    fileDownload.download = 'meeting_notes.doc';
    fileDownload.click();
  };

  const getMarkdownHtml = (text: string | null) => {
    if (!text) return { __html: '' };
    return { __html: typeof marked !== 'undefined' ? marked.parse(text) : text };
  };

  const renderPVMeeting = (data: any) => {
    return (
      <div className="bg-white p-4 sm:p-8 text-slate-800 text-[11pt] leading-relaxed max-w-full overflow-hidden">
        {/* Header Table */}
        <div className="grid grid-cols-12 border border-slate-400 mb-6">
          <div className="col-span-4 border-r border-slate-400 p-2 flex flex-col items-center justify-center min-h-[100px]">
            {logoUrl ? (
              <img src={logoUrl} alt="Golden Carthage Logo" className="max-h-24 object-contain" />
            ) : (
              <div className="flex flex-col items-center text-[#C5A048]">
                <svg className="w-12 h-12 mb-1" viewBox="0 0 100 100" fill="currentColor">
                  <rect x="40" y="5" width="20" height="4" rx="1" />
                  <path d="M35 15 C35 25, 45 35, 55 25 C65 15, 75 25, 75 35" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" />
                  <path d="M45 25 C45 35, 35 45, 25 35" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" />
                  <rect x="42" y="45" width="2" height="25" rx="1" />
                  <rect x="47" y="45" width="2" height="25" rx="1" />
                  <rect x="52" y="45" width="2" height="25" rx="1" />
