            <td style="background-color: #7fb442; color: #ffffff; font-weight: bold; padding: 8pt; border: 1pt solid #94a3b8;">EQUIPE CONCERNÉE :</td>
            <td style="border: 1pt solid #94a3b8; padding: 8pt;">${data.team || '________________'}</td>
          </tr>
          <tr>
            <td style="background-color: #7fb442; color: #ffffff; font-weight: bold; padding: 8pt; border: 1pt solid #94a3b8;">ORDRE DU JOUR :</td>
            <td style="border: 1pt solid #94a3b8; padding: 8pt;">${data.agenda || '________________'}</td>
          </tr>
        </table>

        <!-- Attendees -->
