          <tr style="background-color: #f1f5f9; font-weight: bold; text-align: left;">
            <th style="border: 1pt solid #94a3b8; padding: 8pt;">NOM ET PRÉNOM</th>
            <th style="border: 1pt solid #94a3b8; padding: 8pt;">VISA</th>
            <th style="border: 1pt solid #94a3b8; padding: 8pt;">FONCTION</th>
          </tr>
          ${attendeesHtml}
        </table>

        <p style="font-style: italic; font-size: 11pt; margin-bottom: 10pt;">
