          <span style="font-weight: bold; text-decoration: underline;">${data.objective || 'Discussion générale'}</span>
        </p>
        <p style="font-size: 11pt; margin-bottom: 15pt;">Ci-dessous l'état des lieux pour un suivi des actions :</p>

        <!-- Report Body -->
        <div style="margin-bottom: 25pt;">
          <h3 style="font-weight: bold; text-decoration: underline; font-size: 13pt; margin-bottom: 8pt; color: #0f172a;">RAPPORT SUR LES RÉSULTATS DE RÉUNION :</h3>
          <div style="border: 1pt solid #e2e8f0; padding: 15pt; background-color: #fdfdfd; min-height: 120pt; line-height: 1.6;">
            ${data.report ? data.report.replace(/\n/g, '<br/>') : 'Aucun rapport généré.'}
          </div>
        </div>

        <!-- Action Items -->
        <h3 style="font-weight: bold; text-decoration: underline; font-size: 13pt; margin-bottom: 10pt; color: #0f172a;">A FAIRE :</h3>
        <table style="width: 100%; border: 1pt solid #94a3b8;">
          <tr style="background-color: #7fb442; color: #ffffff; font-weight: bold; text-align: center;">
            <td style="border: 1pt solid #94a3b8; padding: 8pt; color: #ffffff;">ACTIONS À FAIRES</td>
            <td style="border: 1pt solid #94a3b8; padding: 8pt; color: #ffffff;">RESPONSABLE DE RÉALISATION</td>
            <td style="border: 1pt solid #94a3b8; padding: 8pt; color: #ffffff;">ÉCHÉANCE</td>
            <td style="border: 1pt solid #94a3b8; padding: 8pt; color: #ffffff;">SUIVI DE RÉALISATION</td>
          </tr>
          ${tasksHtml}
        </table>

        <!-- Footer -->
        <div style="margin-top: 50pt; border-top: 0.5pt solid #e2e8f0; padding-top: 15pt; text-align: center; font-size: 8pt; color: #64748b; font-style: italic;">
          Ce document est la propriété de l'hôtel Golden Carthage Tunis. Toute reproduction du document est prohibée.
        </div>
      </body>
      </html>
    `;
  };

  const handleExportWord = () => {
    // 1. Check if we have an uploaded Word template to fill
    if (state.jsonResult && wordTemplateFile && templateMode === 'word_template') {
       try {
         const zip = new PizZip(wordTemplateFile);
         const doc = new docxtemplater(zip, {
            paragraphLoop: true,
            linebreaks: true,
            nullGetter: () => ""
         });
         doc.render(state.jsonResult);
         const out = doc.getZip().generate({
            type: "blob",
            mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
         });
         saveAs(out, `filled_${wordTemplateName || 'document.docx'}`);
       } catch (error: any) {
          alert("Error generating Word document from template.");
       }
       return;
    }

    // 2. Specialized PV Meeting Export (Rich Layout)
    if (templateMode === 'pv_meeting') {
      let data = state.jsonResult;

      // Fallback: If AI returned text that looks like JSON but parsing failed in state
      if (!data && state.text) {
        try {
          const possibleJson = state.text.match(/\{[\s\S]*\}/);
          if (possibleJson) data = JSON.parse(possibleJson[0]);
        } catch (e) {}
      }

      if (data) {
        const sourceHTML = generatePVWordHtml(data);
        const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
        const fileDownload = document.createElement("a");
        fileDownload.href = source;
        fileDownload.download = `PV_Reunion_${data.date?.replace(/\//g, '-') || 'Export'}.doc`;
        fileDownload.click();
        return;
      }
    }

    // 3. Fallback: Simple Markdown to Word Export
    if (!state.text) {
      alert("No content to export.");
      return;
    }

    let htmlContent = typeof marked !== 'undefined' ? marked.parse(state.text) : `<pre>${state.text}</pre>`;
    const header = "<html><head><meta charset='utf-8'><style>body{font-family: Calibri, Arial;}</style></head><body>";
