        .border-box { border: 1pt solid #94a3b8; }
      </style>
      </head>
      <body lang="FR">
        <!-- Header Section -->
        <table style="width: 100%; border: 1pt solid #94a3b8; margin-bottom: 15pt;">
          <tr>
            <td style="width: 35%; border-right: 1pt solid #94a3b8; text-align: center; padding: 10pt; vertical-align: middle;">${logoHtml}</td>
            <td style="width: 35%; border-right: 1pt solid #94a3b8; text-align: center; padding: 10pt; vertical-align: middle; font-size: 18pt; font-weight: bold; font-style: italic; text-transform: uppercase;">PV de réunion</td>
            <td style="width: 30%; font-size: 9pt; text-transform: uppercase; padding: 0;">
              <div style="border-bottom: 1pt solid #94a3b8; padding: 3pt 5pt;">REF: <span style="font-family: monospace;">${data.ref || 'QUA-ENR-03'}</span></div>
              <div style="border-bottom: 1pt solid #94a3b8; padding: 3pt 5pt;">VERSION: <span style="font-family: monospace;">${data.version || '00'}</span></div>
              <div style="border-bottom: 1pt solid #94a3b8; padding: 3pt 5pt;">DATE: <span style="font-family: monospace;">${data.date || new Date().toLocaleDateString('fr-FR')}</span></div>
              <div style="padding: 3pt 5pt;">PAGE: <span style="font-family: monospace;">1 SUR 1</span></div>
            </td>
          </tr>
        </table>

        <!-- PV Number Bar -->
